const KWH_PER_GALLON_DIESEL = 38.5; // Approximate KWH output per gallon of diesel/propane equivalent from a generator, considering efficiency.
const MAX_DURATION_DAYS_FOR_SCORE = 7; // Max duration to fully achieve points for duration component
const MAX_POWER_ADEQUACY_SCORE = 25;
const MAX_DURATION_SCORE = 30;
const MAX_EFFICIENCY_SCORE = 15;
const MAX_SOLAR_SCORE = 20;
const MAX_COMMUNITY_SCORE = 10;

// Input validation and defaults, ensuring non-negative values
const essentialDailyLoadKWH = Math.max(0, inputs.essentialDailyLoadKWH || 0);
const peakEssentialLoadKW = Math.max(0, inputs.peakEssentialLoadKW || 0);
const backupPowerCapacityKW = Math.max(0, inputs.backupPowerCapacityKW || 0);
const backupEnergyStorageKWH = Math.max(0, inputs.backupEnergyStorageKWH || 0);
const generatorFuelStorageGallons = Math.max(0, inputs.generatorFuelStorageGallons || 0);
const solarPVCapacityKW = Math.max(0, inputs.solarPVCapacityKW || 0);
const averageDailySolarGenerationKWH = Math.max(0, inputs.averageDailySolarGenerationKWH || 0);
const energyEfficiencyRating = Math.max(1, Math.min(5, inputs.energyEfficiencyRating || 1));
const communityResilienceRating = Math.max(1, Math.min(5, inputs.communityResilienceRating || 1));

let resilienceScore = 0;
let backupDurationEstimateDays = 0;
let resilienceCategory = "Vulnerable";

// Component 1: Power Adequacy Score (P_A)
// Assesses if backup power capacity meets peak essential demand.
let powerAdequacyScore = 0;
if (peakEssentialLoadKW > 0) {
    // Provide a proportional score, capping at MAX_POWER_ADEQUACY_SCORE if capacity meets or exceeds demand
    powerAdequacyScore = Math.min(MAX_POWER_ADEQUACY_SCORE, (backupPowerCapacityKW / peakEssentialLoadKW) * MAX_POWER_ADEQUACY_SCORE);
    if (backupPowerCapacityKW >= peakEssentialLoadKW) {
        powerAdequacyScore = MAX_POWER_ADEQUACY_SCORE; // Full points if capacity is sufficient
    }
} else if (backupPowerCapacityKW > 0) { 
    powerAdequacyScore = MAX_POWER_ADEQUACY_SCORE / 2; // Partial credit if no peak load specified but backup exists
}

// Component 2: Energy Duration Score (E_D)
// Calculates how long essential loads can be met by available energy storage + fuel + daily solar.
let generatorPotentialKWH = generatorFuelStorageGallons * KWH_PER_GALLON_DIESEL;
let totalStaticBackupEnergyKWH = backupEnergyStorageKWH + generatorPotentialKWH;

let dailyNetEssentialLoadKWH_for_duration = essentialDailyLoadKWH - averageDailySolarGenerationKWH;

if (dailyNetEssentialLoadKWH_for_duration <= 0) { 
    // Case 1: Solar covers all essential load, or no essential load declared
    if (essentialDailyLoadKWH === 0) {
        backupDurationEstimateDays = 9999; // Effectively infinite if no load
    } else { 
        backupDurationEstimateDays = 9999; // Effectively infinite as solar meets daily needs
    }
} else { 
    // Case 2: There's a net load not covered by solar
    if (totalStaticBackupEnergyKWH > 0) {
        backupDurationEstimateDays = totalStaticBackupEnergyKWH / dailyNetEssentialLoadKWH_for_duration;
    } else {
        backupDurationEstimateDays = 0; // No backup energy, cannot cover net load
    }
}

// Cap duration for scoring purposes to prevent excessively high scores for extremely long durations.
let durationScore = Math.min(MAX_DURATION_SCORE, (backupDurationEstimateDays / MAX_DURATION_DAYS_FOR_SCORE) * MAX_DURATION_SCORE);

// Component 3: Energy Efficiency Score (E_E)
// Direct translation of rating to points, higher efficiency means lower essential load.
let efficiencyScore = (energyEfficiencyRating / 5) * MAX_EFFICIENCY_SCORE;

// Component 4: Solar Self-Sufficiency Score (S_S)
// Rewards for having solar and reducing dependence on grid/backup, especially if it offsets load.
let solarScore = 0;
if (solarPVCapacityKW > 0) {
    // Base score for simply having solar PV
    solarScore += MAX_SOLAR_SCORE * 0.4; 

    // Additional score for how much solar contributes to daily essential load
    if (essentialDailyLoadKWH > 0) {
        // Proportionally award points based on how much of the essential load solar covers
        solarScore += Math.min(MAX_SOLAR_SCORE * 0.6, (averageDailySolarGenerationKWH / essentialDailyLoadKWH) * (MAX_SOLAR_SCORE * 0.6));
    } else if (averageDailySolarGenerationKWH > 0) { 
        // If no essential load but solar exists, it provides maximum self-sufficiency bonus
        solarScore = MAX_SOLAR_SCORE;
    }
}
solarScore = Math.min(solarScore, MAX_SOLAR_SCORE); // Ensure solar score does not exceed its maximum component value

// Component 5: Community Resilience Score (C_R)
// Direct translation of rating to points, reflecting external support potential.
let communityScore = (communityResilienceRating / 5) * MAX_COMMUNITY_SCORE;

// Total Household Energy Resilience Score
resilienceScore = powerAdequacyScore + durationScore + efficiencyScore + solarScore + communityScore;

// Ensure the final score is within the 0-100 range
resilienceScore = Math.min(100, Math.max(0, resilienceScore));

// Categorize the score for interpretability
if (resilienceScore >= 85) {
    resilienceCategory = "Highly Resilient";
} else if (resilienceScore >= 65) {
    resilienceCategory = "Resilient";
} else if (resilienceScore >= 40) {
    resilienceCategory = "Developing Resilience";
} else if (resilienceScore >= 20) {
    resilienceCategory = "Basic Preparedness";
} else {
    resilienceCategory = "Vulnerable";
}

// Return calculated outputs
return {
    resilienceScore: resilienceScore,
    backupDurationEstimate: backupDurationEstimateDays,
    resilienceCategory: resilienceCategory
};
